query:
query MapMarkersDesktop($input: SearchQueryInput!, $markersInput: MarkersInput!, $airportsInput: AirportMarkersInput!, $citiesInput: CityMarkersInput!, $landmarksInput: LandmarkMarkersInput!, $beachesInput: BeachMarkersInput!, $skiResortsInput: SkiResortMarkersInput!, $includeBeachMarkers: Boolean!, $includeSkiMarkers: Boolean!, $includeBundle: Boolean!, $includeCityMarkers: Boolean!, $includeAirportMarkers: Boolean!, $includeLandmarkMarkers: Boolean!) {
  searchQueries {
    search(input: $input) {
      ...PropertyMarkers
      __typename
    }
    __typename
  }
  mapMarkers(markersInput: $markersInput) {
    ...NonPropertyMarkers
    __typename
  }
}

